    "km.mfs.comment.outro": "Tumors with synchronous metastases are excluded. An event occurs when a tumor shows exclusively metachronous metastases for the first time. If a tumor remains metastasis-free, the last vital status date is used as the censoring date.",
    "km.pfs.title": "Progression-free survival",
    "km.pfs.start": "Date of diagnosis",
    "km.pfs.end.0": "Last vital status date without progression",
    "km.pfs.end.1": "Disease progression or death",
    "km.pfs.comment.rule1": " with overall assessment = \"Progression\", \"Divergent course\" or \"Recurrence\".",
    "km.pfs.comment.rule2": "A later (second) primary tumor is not counted as progression; observation is censored at the diagnosis date of the second tumor (competing event).",
    "km.pfs.comment.outro": "The period until progression or death is considered. The last vital status date is used as the censoring date if no event occurs.",
    "km.sap.title": "Survival after progression",
    "km.sap.start": "Date of disease progression",
    "km.sap.end.0": "Last vital status date",
    "km.sap.end.1": "Death of the patient",
