    "km.sap.comment.rule2": "Occurrence of a later tumor; the diagnosis date is treated as the progression date.",
    "km.sap.comment.outro": "The first available progression time point is used as the start. The time span to death or to the last vital status update after progression is considered. If no event occurs, the last vital status date is used as the censoring date.",
    "km.rfs.title": "Recurrence-free survival",
    "km.rfs.start": "Date of diagnosis",
    "km.rfs.end.0": "Last vital status date without recurrence",
    "km.rfs.end.1": "Occurrence of a recurrence",
