    "km.rfs.comment.rule2": " lymphNodeState = \"Recurrence\" or \"New\" (configurable via OVIS_RULE_PP_LYMPHNODESTATE_REZIDIV_*).",
    "km.rfs.comment.rule3": " tumorState starts with \"Recurrence\" (configurable via OVIS_RULE_PP_TUMORSTATE_REZIDIV_*).",
    "km.rfs.comment.rule4": "Biochemical recurrence: biochemRecurrence = \"Yes\" (configurable via OVIS_RULE_PP_BIOCHEMRECURRENCE_REZIDIV_*).",
